# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit

// MARK: - Password Reset Models

struct PasswordResetDeepLink {
    let token: String
    let email: String?
    let expiresAt: Date?
    
    init?(url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return nil
        }
        
        // Validate the host and path
        guard components.host == "myapp.com",
              components.path == "/reset-password" else {
            return nil
        }
        
        // Parse query parameters
        let queryItems = components.queryItems ?? []
        
        guard let token = queryItems.first(where: { $0.name == "token" })?.value,
              !token.isEmpty else {
            return nil
        }
        
        self.token = token
        self.email = queryItems.first(where: { $0.name == "email" })?.value
        
        if let expiresString = queryItems.first(where: { $0.name == "expires" })?.value,
           let expiresInterval = TimeInterval(expiresString) {
            self.expiresAt = Date(timeIntervalSince1970: expiresInterval)
        } else {
            self.expiresAt = nil
        }
    }
    
    var isExpired: Bool {
        guard let expiresAt = expiresAt else {
            return false // If no expiry, let the server validate
        }
        return Date() > expiresAt
    }
}

// MARK: - Universal Link Router

enum DeepLinkDestination {
    case passwordReset(PasswordResetDeepLink)
    case unknown
}

class UniversalLinkRouter {
    
    static let shared = UniversalLinkRouter()
    
    private let supportedHosts = ["myapp.com", "www.myapp.com"]
    
    private init() {}
    
    func canHandle(url: URL) -> Bool {
        guard let host = url.host else { return false }
        return supportedHosts.contains(host)
    }
    
    func route(url: URL) -> DeepLinkDestination {
        guard canHandle(url: url) else {
            return .unknown
        }
        
        let path = url.path
        
        switch path {
        case "/reset-password":
            if let deepLink = PasswordResetDeepLink(url: url) {
                return .passwordReset(deepLink)
            }
            return .unknown
        default:
            return .unknown
        }
    }
}

// MARK: - Navigation Coordinator

protocol NavigationCoordinatorDelegate: AnyObject {
    func coordinatorDidRequestPasswordReset(with deepLink: PasswordResetDeepLink)
    func coordinatorDidEncounterInvalidLink()
    func coordinatorDidEncounterExpiredLink()
}

class DeepLinkNavigationCoordinator {
    
    static let shared = DeepLinkNavigationCoordinator()
    
    weak var delegate: NavigationCoordinatorDelegate?
    
    private var pendingDeepLink: PasswordResetDeepLink?
    private var isAppReady = false
    
    private init() {}
    
    func markAppReady() {
        isAppReady = true
        processPendingDeepLink()
    }
    
    func handleUniversalLink(_ url: URL) -> Bool {
        let router = UniversalLinkRouter.shared
        let destination = router.route(url: url)
        
        switch destination {
        case .passwordReset(let deepLink):
            if deepLink.isExpired {
                delegate?.coordinatorDidEncounterExpiredLink()
                return true
            }
            
            if isAppReady {
                navigateToPasswordReset(with: deepLink)
            } else {
                pendingDeepLink = deepLink
            }
            return true
            
        case .unknown:
            delegate?.coordinatorDidEncounterInvalidLink()
            return false
        }
    }
    
    private func processPendingDeepLink() {
        guard let deepLink = pendingDeepLink else { return }
        pendingDeepLink = nil
        
        if deepLink.isExpired {
            delegate?.coordinatorDidEncounterExpiredLink()
        } else {
            navigateToPasswordReset(with: deepLink)
        }
    }
    
    private func navigateToPasswordReset(with deepLink: PasswordResetDeepLink) {
        DispatchQueue.main.async { [weak self] in
            self?.delegate?.coordinatorDidRequestPasswordReset(with: deepLink)
            self?.presentPasswordResetScreen(with: deepLink)
        }
    }
    
    private func presentPasswordResetScreen(with deepLink: PasswordResetDeepLink) {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let rootViewController = windowScene.windows.first?.rootViewController else {
            return
        }
        
        let passwordResetVC = PasswordResetViewController(deepLink: deepLink)
        let navigationController = UINavigationController(rootViewController: passwordResetVC)
        navigationController.modalPresentationStyle = .fullScreen
        
        // Dismiss any existing presented view controllers first
        let topVC = Self.topViewController(from: rootViewController)
        topVC.present(navigationController, animated: true)
    }
    
    private static func topViewController(from viewController: UIViewController) -> UIViewController {
        if let presented = viewController.presentedViewController {
            return topViewController(from: presented)
        }
        if let nav = viewController as? UINavigationController,
           let visible = nav.visibleViewController {
            return topViewController(from: visible)
        }
        if let tab = viewController as? UITabBarController,
           let selected = tab.selectedViewController {
            return topViewController(from: selected)
        }
        return viewController
    }
}

